-- Mercedes-Benz: wipe old plans+tiers, re-seed with correct post-OEM tier ranges
DELETE FROM tiers WHERE plan_id IN (
  SELECT p.id FROM plans p
  JOIN variants v ON p.variant_id = v.id
  JOIN models m ON v.model_id = m.id
  JOIN brands b ON m.brand_id = b.id
  WHERE b.name = 'Mercedes-Benz'
);
DELETE FROM plans WHERE variant_id IN (
  SELECT v.id FROM variants v
  JOIN models m ON v.model_id = m.id
  JOIN brands b ON m.brand_id = b.id
  WHERE b.name = 'Mercedes-Benz'
);

